Def:
= 'Displays data for last ' &
  Pick(
    Match($(vOpsScorecardMonthRange), 12, 18, 24),
    '12 months: ' & min({<[Date Interval]={"Last 12 Months"}>} Date) & ' to ' & max({<[Date Interval]={"Last 12 Months"}>} Date),
    '18 months: ' & min({<[Date Interval]={"Last 18 Months"}>} Date) & ' to ' & max({<[Date Interval]={"Last 18 Months"}>} Date),
    '24 months: ' & min({<[Date Interval]={"Last 24 Months"}>} Date) & ' to ' & max({<[Date Interval]={"Last 24 Months"}>} Date)
  )

// Legacy expression
//'Displays data for rolling '&Pick(Match($(vOpsScorecardMonthRange),12,3),'13 months: '& min({<Rolling13MonthFlag={Yes}>}Date) & ' to ' & max({<Rolling13MonthFlag={Yes}>}Date),'4 months: '& min({<Rolling4MonthFlag={Yes}>}Date) & ' to ' & max({<Rolling4MonthFlag={Yes}>}Date))

//Legacy
//'Displays data for rolling '&Pick(Match($(vOpsScorecardMonthRange),12,3),'13 months: '& min({<Rolling13MonthFlag={Yes}>}Date) & ' to ' & max({<Rolling13MonthFlag={Yes}>}Date),'4 months: '& min({<Rolling4MonthFlag={Yes}>}Date) & ' to ' & max({<Rolling4MonthFlag={Yes}>}Date))

DefExpanded:
= 'Displays data for last ' &
  Pick(
    Match(12, 12, 18, 24),
    '12 months: ' & min({<[Date Interval]={"Last 12 Months"}>} Date) & ' to ' & max({<[Date Interval]={"Last 12 Months"}>} Date),
    '18 months: ' & min({<[Date Interval]={"Last 18 Months"}>} Date) & ' to ' & max({<[Date Interval]={"Last 18 Months"}>} Date),
    '24 months: ' & min({<[Date Interval]={"Last 24 Months"}>} Date) & ' to ' & max({<[Date Interval]={"Last 24 Months"}>} Date)
  )

// Legacy expression
//'Displays data for rolling '&Pick(Match($(vOpsScorecardMonthRange),12,3),'13 months: '& min({<Rolling13MonthFlag={Yes}>}Date) & ' to ' & max({<Rolling13MonthFlag={Yes}>}Date),'4 months: '& min({<Rolling4MonthFlag={Yes}>}Date) & ' to ' & max({<Rolling4MonthFlag={Yes}>}Date))

//Legacy
//'Displays data for rolling '&Pick(Match($(vOpsScorecardMonthRange),12,3),'13 months: '& min({<Rolling13MonthFlag={Yes}>}Date) & ' to ' & max({<Rolling13MonthFlag={Yes}>}Date),'4 months: '& min({<Rolling4MonthFlag={Yes}>}Date) & ' to ' & max({<Rolling4MonthFlag={Yes}>}Date))

Def:
=If(
    (
        (
            $(=Pick(Match(vScorecardUnitsCheck, 0, 1), 0, '[CCA TVI Unit Rating Ops]')) * $(vScorecardOpsUnitWeight)
        ) + 
        (
            $(=Pick(Match(vScorecardTurnTimeCheck, 0, 1), 0, '[CCA TVI Turn Times Rating Ops]')) * $(vScorecardOpsTurnTimeWeight)
        ) +
        (
            $(=Pick(Match(vScorecardComplexityCheck, 0, 1), 0, '[CCA TVI Loan Complexity Rating Ops]')) * $(vScorecardOpsComplexityWeight)
        )
    ) /
    (
        $(vScorecardOpsUnitWeight) + $(vScorecardOpsTurnTimeWeight) + $(vScorecardOpsComplexityWeight)
    ) >= 120,
    '#0e6c8b',

    If(
        (
            (
                $(=Pick(Match(vScorecardUnitsCheck, 0, 1), 0, '[CCA TVI Unit Rating Ops]')) * $(vScorecardOpsUnitWeight)
            ) + 
            (
                $(=Pick(Match(vScorecardTurnTimeCheck, 0, 1), 0, '[CCA TVI Turn Times Rating Ops]')) * $(vScorecardOpsTurnTimeWeight)
            ) +
            (
                $(=Pick(Match(vScorecardComplexityCheck, 0, 1), 0, '[CCA TVI Loan Complexity Rating Ops]')) * $(vScorecardOpsComplexityWeight)
            )
        ) /
        (
            $(vScorecardOpsUnitWeight) + $(vScorecardOpsTurnTimeWeight) + $(vScorecardOpsComplexityWeight)
        ) >= 80,
        '#83c69b',

        '#b4df95'
    )
)

DefExpanded:
=If(
    (
        (
            [CCA TVI Unit Rating Ops] * 7
        ) + 
        (
            [CCA TVI Turn Times Rating Ops] * 1.5
        ) +
        (
            [CCA TVI Loan Complexity Rating Ops] * 1.5
        )
    ) /
    (
        7 + 1.5 + 1.5
    ) >= 120,
    '#0e6c8b',

    If(
        (
            (
                [CCA TVI Unit Rating Ops] * 7
            ) + 
            (
                [CCA TVI Turn Times Rating Ops] * 1.5
            ) +
            (
                [CCA TVI Loan Complexity Rating Ops] * 1.5
            )
        ) /
        (
            7 + 1.5 + 1.5
        ) >= 80,
        '#83c69b',

        '#b4df95'
    )
)

Def:
=If(
    (
        (
            $(=Pick(Match(vScorecardUnitsCheck_4Months, 0, 1), 0, '[CCA TVI Unit Rating Ops_4Months]')) * $(vScorecardOpsUnitWeight)
        ) + 
        (
            $(=Pick(Match(vScorecardTurnTimeCheck_4Months, 0, 1), 0, '[CCA TVI Turn Times Rating Ops_4Months]')) * $(vScorecardOpsTurnTimeWeight)
        ) +
        (
            $(=Pick(Match(vScorecardComplexityCheck_ShortTerm, 0, 1), 0, '[CCA TVI Loan Complexity Rating Ops_ShortTerm]')) * $(vScorecardOpsComplexityWeight)
        )
    ) /
    (
        $(vScorecardOpsUnitWeight) + $(vScorecardOpsTurnTimeWeight) + $(vScorecardOpsComplexityWeight)
    ) >= 120,
    '#0e6c8b',

    If(
        (
            (
                $(=Pick(Match(vScorecardUnitsCheck_4Months, 0, 1), 0, '[CCA TVI Unit Rating Ops_4Months]')) * $(vScorecardUnitWeight)
            ) + 
            (
                $(=Pick(Match(vScorecardTurnTimeCheck_4Months, 0, 1), 0, '[CCA TVI Turn Times Rating Ops_4Months]')) * $(vScorecardTurnTimeWeight)
            ) +
            (
                $(=Pick(Match(vScorecardComplexityCheck_ShortTerm, 0, 1), 0, '[CCA TVI Loan Complexity Rating Ops_ShortTerm]')) * $(vScorecardOpsComplexityWeight)
            )
        ) /
        (
            $(vScorecardOpsUnitWeight) + $(vScorecardOpsTurnTimeWeight) + $(vScorecardOpsComplexityWeight)
        ) >= 80,
        '#83c69b',

        '#b4df95'
    )
)

DefExpanded:
=If(
    (
        (
            [CCA TVI Unit Rating Ops_4Months] * 7
        ) + 
        (
            [CCA TVI Turn Times Rating Ops_4Months] * 1.5
        ) +
        (
            [CCA TVI Loan Complexity Rating Ops_ShortTerm] * 1.5
        )
    ) /
    (
        7 + 1.5 + 1.5
    ) >= 120,
    '#0e6c8b',

    If(
        (
            (
                [CCA TVI Unit Rating Ops_4Months] * 2
            ) + 
            (
                [CCA TVI Turn Times Rating Ops_4Months] * 0.5
            ) +
            (
                [CCA TVI Loan Complexity Rating Ops_ShortTerm] * 1.5
            )
        ) /
        (
            7 + 1.5 + 1.5
        ) >= 80,
        '#83c69b',

        '#b4df95'
    )
)

