Def:
=If(
    (
        (
            $(=Pick(Match(vScorecardUnitsCheck, 0, 1), 0, '[CCA TVI Unit Rating Ops]')) * $(vScorecardOpsUnitWeight)
        ) + 
        (
            $(=Pick(Match(vScorecardTurnTimeCheck, 0, 1), 0, '[CCA TVI Turn Times Rating Ops]')) * $(vScorecardOpsTurnTimeWeight)
        ) +
        (
            $(=Pick(Match(vScorecardComplexityCheck, 0, 1), 0, '[CCA TVI Loan Complexity Rating Ops]')) * $(vScorecardOpsComplexityWeight)
        )
    ) /
    (
        $(vScorecardOpsUnitWeight) + $(vScorecardOpsTurnTimeWeight) + $(vScorecardOpsComplexityWeight)
    ) >= 120,
    '#0e6c8b',

    If(
        (
            (
                $(=Pick(Match(vScorecardUnitsCheck, 0, 1), 0, '[CCA TVI Unit Rating Ops]')) * $(vScorecardOpsUnitWeight)
            ) + 
            (
                $(=Pick(Match(vScorecardTurnTimeCheck, 0, 1), 0, '[CCA TVI Turn Times Rating Ops]')) * $(vScorecardOpsTurnTimeWeight)
            ) +
            (
                $(=Pick(Match(vScorecardComplexityCheck, 0, 1), 0, '[CCA TVI Loan Complexity Rating Ops]')) * $(vScorecardOpsComplexityWeight)
            )
        ) /
        (
            $(vScorecardOpsUnitWeight) + $(vScorecardOpsTurnTimeWeight) + $(vScorecardOpsComplexityWeight)
        ) >= 80,
        '#83c69b',

        '#b4df95'
    )
)

DefExpanded:
=If(
    (
        (
            [CCA TVI Unit Rating Ops] * 7
        ) + 
        (
            [CCA TVI Turn Times Rating Ops] * 1.5
        ) +
        (
            [CCA TVI Loan Complexity Rating Ops] * 1.5
        )
    ) /
    (
        7 + 1.5 + 1.5
    ) >= 120,
    '#0e6c8b',

    If(
        (
            (
                [CCA TVI Unit Rating Ops] * 7
            ) + 
            (
                [CCA TVI Turn Times Rating Ops] * 1.5
            ) +
            (
                [CCA TVI Loan Complexity Rating Ops] * 1.5
            )
        ) /
        (
            7 + 1.5 + 1.5
        ) >= 80,
        '#83c69b',

        '#b4df95'
    )
)

