Def:
Avg(
	Aggr(
		Sum(
			{<Rolling13MonthFlag*={Yes}, 
			DateType*={'$(vCCA_TVI_DateType)'}, 
			[Consolidated Channels]*={'$(vCCA_ChannelGroup)'}, 
			$(vCCA_ScorecardMissingLevel),
			$(vCCA_ScorecardAggrLevel)={"=$(eCCA_TVI_Score_13_Months) > 0"}>}
			[Loan Amount]
		),
	$(vCCA_ScorecardAggrLevel)
	)
)

Count(
	{$<Rolling13MonthFlag*={Yes},
	DateType={'Application'},
	[Consolidated Channels]*={'$(vCCA_ChannelGroup)'}, 
	$(vCCA_ScorecardMissingLevel),
	[Current Loan Status]*={"*withdraw*","*not accepted*","*incomp*"},
	$(vCCA_ScorecardAggrLevel)={"=$(eCCA_TVI_Score_13_Months) > 0"}
	>}
[Loan Number]
)

Count(
	{$<Rolling13MonthFlag*={Yes},
	DateType={'Application'},
	[Consolidated Channels]*={'$(vCCA_ChannelGroup)'}, 
	$(vCCA_ScorecardMissingLevel),
	[Current Loan Status]*={"*denied*"},
	$(vCCA_ScorecardAggrLevel)={"=$(eCCA_TVI_Score_13_Months) > 0"}
	>}
[Loan Number]
)

Avg(
	Aggr(
		Avg(
			{<Rolling13MonthFlag*={Yes}, 
			DateType*={'$(vCCA_TVI_DateType)'}, 
			[Consolidated Channels]*={'$(vCCA_ChannelGroup)'}, 
			$(vCCA_ScorecardMissingLevel),
			$(vCCA_ScorecardAggrLevel)={"=$(eCCA_TVI_Score_13_Months) > 0"}>}
			[Number Of Conditions]
        ),
	$(vCCA_ScorecardAggrLevel)
	)
)

